t.script:
/**/
(function () {
    'use strict';

    document.addEventListener('DOMContentLoaded', function () {
        var historyEl = document.getElementById('ssai-chat-history');
        var emptyHint = document.getElementById('ssai-empty-hint');
        var formEl    = document.getElementById('ssai-composer');
        var inputEl   = document.getElementById('ssai-question');
        var modeSelEl = document.getElementById('ssai-mode-select');
        var modeHidEl = document.getElementById('ssai-mode');
        var sendBtn   = document.getElementById('ssai-send');

        if (!historyEl || !formEl || !inputEl || !sendBtn) {
            console.error('Steamships AI: missing DOM nodes');
            return;
        }

        // Keep the hidden mode field in sync with the visible select.
        if (modeSelEl && modeHidEl) {
            modeSelEl.addEventListener('change', function () {
                modeHidEl.value = modeSelEl.value;
            });
        }

        function escapeHtml(s) {
            if (s === undefined || s === null) return '';
            return String(s)
                .replace(/&amp;/g, '&amp;amp;')
                .replace(/&lt;/g, '&amp;lt;')
                .replace(/&gt;/g, '&amp;gt;')
                .replace(/"/g, '&amp;quot;')
                .replace(/'/g, '&#39;');
        }

        function stripCommonHtml(value) {
            return String(value || '')
                .replace(/<br\s*\/?\s*>/gi, '\n')
                .replace(/<\/p>/gi, '\n')
                .replace(/<\/?(?:p|strong|b|em|ul|ol|li|h[1-6])\b[^>]*>/gi, '');
        }

        function renderMarkdownInline(value) {
            return escapeHtml(value).replace(/\*\*([^*]+)\*\*/g, '<strong>$1</strong>');
        }

        function renderMarkdown(value) {
            var lines = stripCommonHtml(value).replace(/\r\n/g, '\n').split('\n');
            var html = [];
            var listType = null;

            function closeList() {
                if (listType) {
                    html.push('</' + listType + '>');
                    listType = null;
                }
            }

            function openList(type) {
                if (listType !== type) {
                    closeList();
                    html.push('<' + type + ' class="ssai-md-list">');
                    listType = type;
                }
            }

            lines.forEach(function (line) {
                var trimmed = line.trim();
                var heading;
                var bullet;
                var numbered;
                if (!trimmed) {
                    closeList();
                    return;
                }
                heading = trimmed.match(/^###\s+(.+)$/);
                if (heading) {
                    closeList();
                    html.push('<h4 class="ssai-md-heading">' + renderMarkdownInline(heading[1]) + '</h4>');
                    return;
                }
                bullet = trimmed.match(/^[-*]\s+(.+)$/);
                if (bullet) {
                    openList('ul');
                    html.push('<li>' + renderMarkdownInline(bullet[1]) + '</li>');
                    return;
                }
                numbered = trimmed.match(/^\d+\.\s+(.+)$/);
                if (numbered) {
                    openList('ol');
                    html.push('<li>' + renderMarkdownInline(numbered[1]) + '</li>');
                    return;
                }
                closeList();
                html.push('<p class="ssai-md-p">' + renderMarkdownInline(trimmed) + '</p>');
            });
            closeList();
            return html.join('') || '<p class="ssai-md-p text-muted small">No answer returned.</p>';
        }

        function scrollToBottom() {
            historyEl.scrollTop = historyEl.scrollHeight;
        }

        function appendMessage(role, html) {
            if (emptyHint && emptyHint.parentNode) {
                emptyHint.parentNode.removeChild(emptyHint);
            }
            var wrapper = document.createElement('div');
            wrapper.className = 'mb-3';
            var labelCls = role === 'user' ? 'text-primary' : 'text-success';
            var label = role === 'user' ? 'You' : 'Assistant';
            wrapper.innerHTML =
                '<div class="fw-semibold small ' + labelCls + ' mb-1">'
                + label + '</div>'
                + '<div class="ssai-bubble p-2 px-3 rounded border bg-light-subtle">'
                + html + '</div>';
            historyEl.appendChild(wrapper);
            scrollToBottom();
        }

        function appendLoading() {
            if (emptyHint && emptyHint.parentNode) {
                emptyHint.parentNode.removeChild(emptyHint);
            }
            var loading = document.createElement('div');
            loading.id = 'ssai-loading';
            loading.className = 'mb-3';
            loading.innerHTML =
                '<div class="fw-semibold small text-success mb-1">Assistant</div>'
                + '<div class="ssai-bubble p-2 px-3 rounded border bg-light-subtle text-muted">'
                + '<span class="spinner-border spinner-border-sm me-2" role="status"></span>'
                + 'Thinking…'
                + '</div>';
            historyEl.appendChild(loading);
            scrollToBottom();
        }

        function removeLoading() {
            var el = document.getElementById('ssai-loading');
            if (el && el.parentNode) {
                el.parentNode.removeChild(el);
            }
        }

        function renderChunks(chunks) {
            if (!chunks || chunks.length === 0) {
                return '';
            }
            var html = '<div class="small text-muted mb-2">'
                + 'Top ' + chunks.length + ' sources from the corpus:'
                + '</div>';
            chunks.forEach(function (c, idx) {
                var name = c.doc_name || c.doc_id || ('Source ' + (idx + 1));
                var section = c.section || '';
                var score = (typeof c.score === 'number')
                    ? ' · score ' + c.score.toFixed(2)
                    : '';
                var file = c.filename || '';
                html +=
                    '<div class="mb-2 pb-2 border-bottom">'
                    + '<div class="fw-semibold small">'
                    + (idx + 1) + '. '
                    + escapeHtml(name) + '</div>'
                    + '<div class="text-muted small mb-1">'
                    + escapeHtml(section) + escapeHtml(score)
                    + (file ? ' · ' + escapeHtml(file) : '')
                    + '</div>'
                    + '<div class="small" style="white-space: pre-wrap;">'
                    + escapeHtml(c.text || '') + '</div>'
                    + '</div>';
            });
            return html;
        }

        function sourceLabel(source) {
            if (typeof source === 'string') return source;
            if (source) return source.name || source.doc_name || source.filename || source.section || source.title || 'Source';
            return 'Source';
        }

        function renderSourceChips(sources, chunks) {
            var labels = sources && sources.length ? sources : (chunks || []).map(sourceLabel);
            if (!labels || !labels.length) return '';
            return '<div class="ssai-source-chips mt-2">' + labels.slice(0, 6).map(function (source) {
                return '<span class="badge rounded-pill text-bg-info-subtle border border-info-subtle text-info-emphasis me-1 mb-1"><strong>'
                    + escapeHtml(sourceLabel(source)) + '</strong></span>';
            }).join('') + '</div>';
        }

        function renderAnswer(answer) {
            if (!answer || !answer.trim()) {
                return '<div class="text-muted small">'
                    + 'I don\'t know based on the available documents. '
                    + 'Please ask the Sales Operations team.</div>';
            }
            return '<div class="ssai-answer">' + renderMarkdown(answer) + '</div>';
        }

        function appendAssistantAnswer(payload) {
            var wrapper = document.createElement('div');
            wrapper.className = 'mb-3';

            var html = '<div class="fw-semibold small text-success mb-1">'
                + 'Assistant</div>'
                + '<div class="ssai-bubble p-2 px-3 rounded border bg-light-subtle">'
                + renderAnswer(payload.answer || '')
                + renderSourceChips(payload.sources || [], payload.chunks || [])
                + '</div>';

            var chunks = payload.chunks || [];
            if (chunks.length > 0) {
                var toggleId = 'ssai-src-' + Date.now() + '-' + Math.random().toString(36).slice(2, 8);
                html += '<div class="mt-2">'
                    + '<a href="#" class="small text-decoration-none" '
                    + 'data-ssai-toggle="' + toggleId + '">'
                    + 'Show sources (' + chunks.length + ')</a>'
                    + '</div>'
                    + '<div id="' + toggleId + '" class="ssai-sources mt-2" style="display:none;">'
                    + renderChunks(chunks)
                    + '</div>';
            }

            wrapper.innerHTML = html;
            historyEl.appendChild(wrapper);

            // Wire up the collapsible toggle (event delegation
            // would be nicer but this is the smallest change).
            var toggle = wrapper.querySelector('[data-ssai-toggle]');
            var panel = wrapper.querySelector('.ssai-sources');
            if (toggle && panel) {
                toggle.addEventListener('click', function (ev) {
                    ev.preventDefault();
                    var open = panel.style.display !== 'none';
                    panel.style.display = open ? 'none' : 'block';
                    toggle.textContent = (open ? 'Show' : 'Hide')
                        + ' sources (' + chunks.length + ')';
                });
            }

            scrollToBottom();
        }

        function send(question, mode) {
            appendMessage('user', escapeHtml(question));

            var loadingAdded = appendLoading();
            sendBtn.disabled = true;
            inputEl.disabled = true;

            var body = JSON.stringify({
                jsonrpc: '2.0',
                method: 'call',
                params: {
                    question: question,
                    mode: mode
                }
            });

            fetch('/ai/retrieve', {
                method: 'POST',
                credentials: 'same-origin',
                headers: {
                    'Content-Type': 'application/json',
                    'Accept': 'application/json'
                },
                body: body
            })
            .then(function (resp) {
                return resp.json().then(function (json) {
                    return { ok: resp.ok, status: resp.status, json: json };
                });
            })
            .then(function (out) {
                removeLoading();
                if (out.json && out.json.error) {
                    var msg = out.json.error.message || out.json.error.data || 'Unknown error';
                    appendMessage(
                        'assistant',
                        '<div class="text-danger small">Error: '
                        + escapeHtml(msg) + '</div>'
                    );
                    return;
                }
                // Odoo JSON-RPC result lives at .result (or .result.result for our wrapper).
                var payload = (out.json && out.json.result) || null;
                var inner = payload && payload.result ? payload.result : payload;
                if (!inner) {
                    appendMessage(
                        'assistant',
                        '<div class="text-danger small">Empty response from server.</div>'
                    );
                    return;
                }
                if (inner.status === 'error') {
                    appendMessage(
                        'assistant',
                        '<div class="text-danger small">'
                        + escapeHtml(inner.message || 'Unknown error')
                        + '</div>'
                    );
                    return;
                }
                appendAssistantAnswer(inner);
            })
            .catch(function (err) {
                removeLoading();
                appendMessage(
                    'assistant',
                    '<div class="text-danger small">Network error: '
                    + escapeHtml(err && err.message ? err.message : String(err))
                    + '</div>'
                );
            })
            .finally(function () {
                sendBtn.disabled = false;
                inputEl.disabled = false;
                inputEl.focus();
            });
        }

        formEl.addEventListener('submit', function (ev) {
            ev.preventDefault();
            var q = (inputEl.value || '').trim();
            if (!q) return;
            var mode = (modeHidEl && modeHidEl.value) || 'STAFF';
            inputEl.value = '';
            send(q, mode);
        });

        // Ctrl/Cmd + Enter also submits.
        inputEl.addEventListener('keydown', function (ev) {
            if ((ev.ctrlKey || ev.metaKey) && ev.key === 'Enter') {
                ev.preventDefault();
                formEl.dispatchEvent(new Event('submit', { cancelable: true }));
            }
        });

        inputEl.focus();
    });
})();
/**/
